module alu(
    input [31:0] a,
    input [31:0] b,
    input [5:0] aluc,
    output [31:0] r,
    output zero,
    output carry,
    output negative,
    output overflow,
    output flag
);
// ADD, ADDU, SUB, SUBU, AND, OR, XOR, NOR, SLT, SLTU, SLL, SRL, SRA, SLLV, SRLV, SRAV, LUI
parameter ADD = 6'b100000;
parameter ADDU = 6'b100001;
parameter SUB = 6'b100010;
parameter SUBU = 6'b100011;
parameter AND = 6'b100100;
parameter OR = 6'b100101;
parameter XOR = 6'b100110;
parameter NOR = 6'b100111;
parameter SLT = 6'b101010;
parameter SLTU = 6'b101011;
parameter SLL = 6'b000000;
parameter SRL = 6'b000010;
parameter SRA = 6'b000011;
parameter SLLV = 6'b000100;
parameter SRLV = 6'b000110;
parameter SRAV = 6'b000111;
parameter LUI = 6'b001111;
    reg [32:0] res;
    wire signed [31:0] a_signed = a;
    wire signed [31:0] b_signed = b;
    wire [4:0] shamt = a[4:0];
    wire [15:0] a_16 = a[31:16];
    assign r = res[31:0];
    assign zero = res[31:0] == 32'b0;
    assign carry = res[32];
    assign negative = res[31];
    assign overflow = (aluc == SUB || aluc == SUBU) ? ((a_signed[31] && !b_signed[31] && !res[31]) || (!a_signed[31] && b_signed[31] && res[31])) : 0;
    assign flag = (aluc == SLT || aluc == SLTU) ? res[0] : 0;
    always @(*) begin
        case (aluc)
            ADD: res = a_signed + b_signed;
            ADDU: res = a + b;
            SUB: res = a_signed - b_signed;
            SUBU: res = a - b;
            AND: res = {1'b0, a & b};
            OR: res = {1'b0, a | b};
            XOR: res = {1'b0, a ^ b};
            NOR: res = {1'b0, ~(a | b)};
            SLT: res = {1'b0, a_signed < b_signed};
            SLTU: res = {1'b0, a < b};
            SLL: res = {1'b0, a << shamt};
            SRL: res = {1'b0, a >> shamt};
            SRA: res = {1'b0, a_signed >>> shamt};
            SLLV: res = {1'b0, a << b[4:0]};
            SRLV: res = {1'b0, a >> b[4:0]};
            SRAV: res = {1'b0, a_signed >>> b[4:0]};
            LUI: res = {a_16, 16'b0};
            default: res = {33{1'bz}};
        endcase
    end
endmodule
